import { auditLogsClient } from '@dynatrace-sdk/client-classic-environment-v2';
import { queryExecutionClient } from '@dynatrace-sdk/client-query';

export default async function () {
  // Step 1: Collect Classic users from Classic Audit Logs API
  const classicUsers: Record<string, { actions: number; lastActivity: number }> = {};
  let nextPageKey: string | undefined = undefined;

  do {
    const params: Record<string, unknown> = nextPageKey
      ? { nextPageKey }
      : { from: $dt_timeframe_from, to: $dt_timeframe_to, sort: '-timestamp', pageSize: 5000, filter: 'category("WEB_UI","CONFIG")' };

    const response = await auditLogsClient.getLogs(params as any);

    if (response.auditLogs) {
      for (const entry of response.auditLogs) {
        if (
          entry.user &&
          entry.user !== 'system' &&
          entry.user !== 'UNKNOWN' &&
          entry.user.includes('@') &&
          !entry.user.includes('@heimdall.dynatrace.com') &&
          !entry.user.includes('@service.sso.dynatrace.com')
        ) {
          const u = entry.user.toLowerCase();
          if (!classicUsers[u]) classicUsers[u] = { actions: 0, lastActivity: 0 };
          classicUsers[u].actions++;
          const ts = typeof entry.timestamp === 'number' ? entry.timestamp : 0;
          if (ts > classicUsers[u].lastActivity) classicUsers[u].lastActivity = ts;
        }
      }
    }
    nextPageKey = response.nextPageKey ?? undefined;
  } while (nextPageKey);

  // Step 2: Get Gen3 active users from Grail
  const now = new Date();
  const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

  const dql = `fetch dt.system.events
| filter event.kind == "AUDIT_EVENT"
| filter event.provider == "API_GATEWAY"
| filter \`request.source\` == "BROWSER"
| filter \`user.id\` != "UNKNOWN" AND \`user.id\` != "system"
| lookup [fetch dt.system.events | filter event.kind == "QUERY_EXECUTION_EVENT" | filter contains(toString(\`user.email\`), "@") | filter NOT contains(toString(\`user.email\`), "@heimdall.dynatrace.com") | summarize email = takeFirst(\`user.email\`), by: {\`user.id\`}], sourceField:\`user.id\`, lookupField:\`user.id\`, prefix:"lu."
| fieldsAdd userEmail = coalesce(\`lu.email\`, \`user.id\`)
| filter contains(userEmail, "@")
| summarize gen3Users = collectArray(lower(userEmail)), by:{}
| fields gen3Users`;

  const queryResult = await queryExecutionClient.queryExecute({
    body: {
      query: dql,
      requestTimeoutMilliseconds: 60000,
      defaultTimeframeStart: thirtyDaysAgo.toISOString(),
      defaultTimeframeEnd: now.toISOString()
    }
  });

  // Step 3: Build Gen3 user set
  const gen3Set = new Set<string>();
  if (queryResult.result?.records?.[0]) {
    const record = queryResult.result.records[0] as Record<string, unknown>;
    const userList = record.gen3Users as string[];
    if (userList) {
      for (const u of userList) gen3Set.add(u.toLowerCase());
    }
  }

  // Step 4: Classic-only = in Classic logs AND NOT in Gen3 Grail
  const classicOnly = Object.entries(classicUsers)
    .filter(([user]) => !gen3Set.has(user))
    .map(([user, data]) => ({
      'User': user,
      'Classic Actions': data.actions,
      'Last Activity': data.lastActivity > 0
        ? new Date(data.lastActivity).toISOString().split('T')[0]
        : 'Unknown'
    }))
    .sort((a, b) => b['Classic Actions'] - a['Classic Actions'])
    .slice(0, 25);

  return classicOnly.length > 0
    ? classicOnly
    : [{ 'User': 'No Classic-only users found', 'Classic Actions': 0, 'Last Activity': '-' }];
}

