import { auditLogsClient } from '@dynatrace-sdk/client-classic-environment-v2';
import { queryExecutionClient } from '@dynatrace-sdk/client-query';

export default async function () {
  // Step 1: Get Classic/Gen2 users via audit logs
  const classicUsers = new Set<string>();
  let nextPageKey: string | undefined = undefined;

  do {
    const params: Record<string, unknown> = nextPageKey
      ? { nextPageKey }
      : { from: $dt_timeframe_from, to: $dt_timeframe_to, sort: '-timestamp', pageSize: 5000, filter: 'category("WEB_UI","CONFIG")' };

    const response = await auditLogsClient.getLogs(params as any);

    if (response.auditLogs) {
      for (const entry of response.auditLogs) {
        if (entry.user &&
            entry.user !== 'system' &&
            entry.user !== 'UNKNOWN' &&
            !entry.user.includes('@heimdall.dynatrace.com') &&
            !entry.user.includes('@service.sso.dynatrace.com')) {
          classicUsers.add(entry.user);
        }
      }
    }
    nextPageKey = response.nextPageKey ?? undefined;
  } while (nextPageKey);

  // Step 2: Get Gen3 users from Grail
  const now = new Date();
  const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

  const dql = `fetch dt.system.events
| filter event.kind == "AUDIT_EVENT"
| filter event.provider == "API_GATEWAY"
| filter \`request.source\` == "BROWSER"
| filter \`user.id\` != "UNKNOWN" AND \`user.id\` != "system"
| filter isNotNull(\`dt.app.id\`) AND \`dt.app.id\` != "dynatrace.appshell" AND \`dt.app.id\` != "dynatrace.launcher"
| lookup [fetch dt.system.events | filter event.kind == "QUERY_EXECUTION_EVENT" | filter contains(toString(\`user.email\`), "@") | filter NOT contains(toString(\`user.email\`), "@heimdall.dynatrace.com") | summarize email = first(\`user.email\`), by: {\`user.id\`}], sourceField:\`user.id\`, lookupField:\`user.id\`, prefix:"lu."
| fieldsAdd userEmail = coalesce(\`lu.email\`, \`user.id\`)
| summarize gen3UsersList = collectArray(userEmail), by:{}
| fields gen3UsersList`;

  const queryResult = await queryExecutionClient.queryExecute({
    body: {
      query: dql,
      requestTimeoutMilliseconds: 60000,
      defaultTimeframeStart: thirtyDaysAgo.toISOString(),
      defaultTimeframeEnd: now.toISOString()
    }
  });

  const gen3Users = new Set<string>();
  if (queryResult.result?.records?.[0]) {
    const record = queryResult.result.records[0] as Record<string, unknown>;
    const userList = record.gen3UsersList as string[];
    if (userList) {
      for (const u of userList) {
        gen3Users.add(u);
      }
    }
  }

  // Step 3: Calculate adoption categories
  const allUsers = new Set([...classicUsers, ...gen3Users]);
  let gen3Only = 0;
  let hybrid = 0;
  let classicOnly = 0;

  for (const user of allUsers) {
    const isGen3 = gen3Users.has(user);
    const isClassic = classicUsers.has(user);
    if (isGen3 && !isClassic) gen3Only++;
    else if (isGen3 && isClassic) hybrid++;
    else classicOnly++;
  }

  const totalUsers = allUsers.size;
  const adoptedGen3 = gen3Only + hybrid;

  return [
    { Category: "Gen3 Only", Users: gen3Only },
    { Category: "Hybrid (Both)", Users: hybrid },
    { Category: "Classic Only", Users: classicOnly }
  ];
}

